function processData(input) {
  try {
    // CSV verilerini al
    const data = input.data || [];

    if (!data || data.length === 0) {
      return {
        success: false,
        message: 'İşlenecek veri bulunamadı',
        summary: {}
      };
    }

    // Veri özeti oluştur
    const summary = {
      rowCount: data.length,
      columnCount: Object.keys(data[0] || {}).length,
      columns: Object.keys(data[0] || {}),
      sampleData: data.slice(0, 5),
      missingValues: {}
    };

    // Eksik değerleri kontrol et
    summary.columns.forEach(column => {
      const missingCount = data.filter(row => !row[column]).length;
      summary.missingValues[column] = {
        count: missingCount,
        percentage: (missingCount / data.length * 100).toFixed(2) + '%'
      };
    });

    return {
      success: true,
      data: data,
      summary: summary
    };
  } catch (error) {
    return {
      success: false,
      message: 'Veri işleme hatası: ' + error.message,
      error: error.toString()
    };
  }
}

function processData(input) {
  // Bu fonksiyon gerçek bir grafik oluşturmaz, ancak grafik oluşturma için gerekli verileri hazırlar
  // Gerçek uygulamada, bu veri bir grafik kütüphanesine (Chart.js, D3.js vb.) beslenebilir

  try {
    const analysisText = input.content || '';
    const data = input.data || [];

    if (!data || data.length === 0) {
      return {
        success: false,
        message: 'Grafik oluşturmak için veri bulunamadı'
      };
    }

    // Basit bir grafik konfigürasyonu oluştur
    const chartConfig = {
      type: 'bar', // varsayılan grafik türü
      title: 'Veri Analizi Grafiği',
      xAxis: {
        title: 'Kategoriler',
        categories: []
      },
      yAxis: {
        title: 'Değerler'
      },
      series: []
    };

    // Analiz metninden grafik türünü belirle
    if (analysisText.includes('zaman serisi') || analysisText.includes('trend')) {
      chartConfig.type = 'line';
    } else if (analysisText.includes('dağılım') || analysisText.includes('korelasyon')) {
      chartConfig.type = 'scatter';
    } else if (analysisText.includes('karşılaştırma') || analysisText.includes('oran')) {
      chartConfig.type = 'pie';
    }

    return {
      success: true,
      chartConfig: chartConfig,
      message: 'Grafik konfigürasyonu oluşturuldu'
    };
  } catch (error) {
    return {
      success: false,
      message: 'Grafik oluşturma hatası: ' + error.message,
      error: error.toString()
    };
  }
}

function processData(input) {
  try {
    const analysis = input.content || 'Analiz sonucu bulunamadı';
    const summary = input.summary || {};
    const chartConfig = input.chartConfig || { type: 'bar' };

    // Rapor formatını oluştur
    const report = {
      title: 'Veri Analiz Raporu',
      date: new Date().toLocaleDateString('tr-TR'),
      summary: {
        rowCount: summary.rowCount || 0,
        columnCount: summary.columnCount || 0,
        columns: summary.columns || []
      },
      analysis: analysis,
      charts: [chartConfig],
      conclusions: extractConclusions(analysis),
      recommendations: generateRecommendations(analysis)
    };

    return {
      success: true,
      report: report,
      formattedReport: formatReport(report)
    };
  } catch (error) {
    return {
      success: false,
      message: 'Rapor oluşturma hatası: ' + error.message,
      error: error.toString()
    };
  }
}

// Analizden sonuçları çıkar
function extractConclusions(analysis) {
  // Gerçek uygulamada, bu fonksiyon NLP kullanarak analizden sonuçları çıkarabilir
  // Basit bir örnek olarak, 'sonuç' kelimesini içeren cümleleri alıyoruz
  const conclusions = [];

  if (typeof analysis === 'string') {
    const sentences = analysis.split(/\.\s+/);
    for (const sentence of sentences) {
      if (sentence.toLowerCase().includes('sonuç') || 
          sentence.toLowerCase().includes('önemli') ||
          sentence.toLowerCase().includes('dikkat çekici')) {
        conclusions.push(sentence.trim() + '.');
      }
    }
  }

  return conclusions.length > 0 ? conclusions : ['Belirgin sonuç bulunamadı.'];
}

// Öneriler oluştur
function generateRecommendations(analysis) {
  // Gerçek uygulamada, bu fonksiyon analiz sonuçlarına göre öneriler oluşturabilir
  // Basit bir örnek olarak, 'öneri' kelimesini içeren cümleleri alıyoruz
  const recommendations = [];

  if (typeof analysis === 'string') {
    const sentences = analysis.split(/\.\s+/);
    for (const sentence of sentences) {
      if (sentence.toLowerCase().includes('öner') || 
          sentence.toLowerCase().includes('tavsiye') ||
          sentence.toLowerCase().includes('geliştirilmeli')) {
        recommendations.push(sentence.trim() + '.');
      }
    }
  }

  return recommendations.length > 0 ? recommendations : ['Özel öneri bulunamadı.'];
}

// Raporu formatla
function formatReport(report) {
  // Markdown formatında rapor oluştur
  let markdown = `# ${report.title}\n\n`;
  markdown += `Tarih: ${report.date}\n\n`;

  markdown += `## Veri Özeti\n\n`;
  markdown += `- Satır Sayısı: ${report.summary.rowCount}\n`;
  markdown += `- Sütun Sayısı: ${report.summary.columnCount}\n`;
  markdown += `- Sütunlar: ${report.summary.columns.join(', ')}\n\n`;

  markdown += `## Analiz\n\n${report.analysis}\n\n`;

  markdown += `## Sonuçlar\n\n`;
  for (const conclusion of report.conclusions) {
    markdown += `- ${conclusion}\n`;
  }
  markdown += '\n';

  markdown += `## Öneriler\n\n`;
  for (const recommendation of report.recommendations) {
    markdown += `- ${recommendation}\n`;
  }

  return markdown;
}
